        std::cout << "Collecting events...\n";
        bus.publish(Event{EventType::SensorData, frame * 10, 0});
        bus.publish(Event{EventType::UserInput, frame, 0});

        // Do other work
        std::cout << "Doing game logic...\n";
        std::cout << "Rendering...\n";

