    mutable std::mutex mtx;

public:
    void publish(const Event& e) {
        std::lock_guard<std::mutex> lock(mtx);
        for (auto& h : handlers) {
            h(e);
        }
    }

    void subscribe(EventHandler h) {
        std::lock_guard<std::mutex> lock(mtx);
        handlers.push_back(h);
    }
};
```

